// Build the upsert SQL from the subscription body. The webhook payload is
// 2 nodes upstream (after Init Table) so $input is empty — pull by name.
const webhook = $('POST /webpush/subscribe').first().json;
const body = webhook.body || webhook;
const sub = body.subscription || body;
const userAgent = (webhook.headers && webhook.headers['user-agent']) || body.user_agent || '';

if (!sub?.endpoint || !sub?.keys?.p256dh || !sub?.keys?.auth) {
  return [{ json: { ok: false, error: 'subscription missing endpoint/keys', sql: 'SELECT 1' } }];
}

const esc = s => String(s).replace(/\\/g, '\\\\').replace(/'/g, "''");
const sql = `INSERT INTO push_subscriptions (endpoint, p256dh, auth_key, user_agent) VALUES ('${esc(sub.endpoint)}', '${esc(sub.keys.p256dh)}', '${esc(sub.keys.auth)}', '${esc(userAgent.slice(0, 255))}') ON DUPLICATE KEY UPDATE p256dh = VALUES(p256dh), auth_key = VALUES(auth_key), user_agent = VALUES(user_agent), last_seen = NOW()`;

return [{ json: { ok: true, sql, endpoint: sub.endpoint } }];

const input = $input.first().json;
const body = input.body || input;
const endpoint = body.endpoint;
if (!endpoint) return [{ json: { ok: false, error: 'endpoint required' } }];
const esc = s => String(s).replace(/\\/g, '\\\\').replace(/'/g, "''");
const sql = `DELETE FROM push_subscriptions WHERE endpoint = '${esc(endpoint)}'`;
return [{ json: { ok: true, sql, endpoint } }];

// Bundle subscriptions into the shape the sidecar wants.
const rows = $input.all().map(i => i.json).filter(r => r && r.endpoint);
const payloadInput = $('POST /webpush/send').first().json;
const payload = (payloadInput.body && payloadInput.body.payload) || payloadInput.payload || payloadInput.body || {};

const subscriptions = rows.map(r => ({
  endpoint: r.endpoint,
  keys: { p256dh: r.p256dh, auth: r.auth_key }
}));

return [{ json: { subscriptions, payload, count: subscriptions.length } }];

// Sidecar returned per-subscription results. Drop dead endpoints (gone=true)
// from MySQL so we stop trying.
const sidecar = $json;
const gone = (sidecar.results || []).filter(r => r.gone).map(r => r.endpoint);

let sql = 'SELECT 1';
if (gone.length > 0) {
  const list = gone.map(e => "'" + String(e).replace(/\\/g, '\\\\').replace(/'/g, "''") + "'").join(',');
  sql = `DELETE FROM push_subscriptions WHERE endpoint IN (${list})`;
}

return [{ json: { ...sidecar, _cleanup_sql: sql, _gone_count: gone.length } }];
